MAX_REDIRECTS = 0  # Do not follow redirects; validate each hop explicitly
REQUEST_TIMEOUT = 10  # seconds
MAX_RESPONSE_BYTES = 5 * 1024 * 1024  # 5 MB


class SSRFError(Exception):
    """Raised when a request is blocked due to SSRF protections."""
    pass


def _is_ip_blocked(ip_str: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip_str)
    except ValueError:
        return True  # If we can't parse it, block it
    for network in BLOCKED_CIDR_RANGES:
        if addr in network:
            return True
    return False


def _validate_url(url: str) -> urllib.parse.ParseResult:
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception as exc:
        raise SSRFError(f"Unable to parse URL: {exc}")

    if parsed.scheme not in ALLOWED_SCHEMES:
        raise SSRFError(
            f"Scheme '{parsed.scheme}' is not allowed. Allowed: {ALLOWED_SCHEMES}"
        )

    hostname = parsed.hostname
    if not hostname:
        raise SSRFError("URL must contain a valid hostname.")

    if hostname.lower() in BLOCKED_HOSTNAMES:
        raise SSRFError(f"Hostname '{hostname}' is blocked.")

    port = parsed.port
    if port is not None and port != 443:
        raise SSRFError(f"Port {port} is not allowed. Only port 443 (HTTPS) is permitted.")

    # Resolve hostname and check all resulting IPs *before* making the request
    try:
        addrinfos = socket.getaddrinfo(hostname, port or 443, proto=socket.IPPROTO_TCP)
    except socket.gaierror as exc:
        raise SSRFError(f"DNS resolution failed for '{hostname}': {exc}")

    if not addrinfos:
        raise SSRFError(f"No DNS results for '{hostname}'.")

    for family, _type, _proto, _canonname, sockaddr in addrinfos:
        ip_str = sockaddr[0]
        if _is_ip_blocked(ip_str):
            raise SSRFError(
                f"Resolved IP '{ip_str}' for hostname '{hostname}' is in a blocked range."
            )

    return parsed


def _validate_redirect_target(response: requests.Response) -> None:
    """If the server returned a redirect, validate the Location header."""
    if response.is_redirect or response.is_permanent_redirect:
        location = response.headers.get("Location", "")
        raise SSRFError(
            f"Redirect to '{location}' was blocked. Redirects are not followed."
        )


def fetch_url(url: str, allowed_domains: Optional[Set[str]] = None) -> str:
    """
    Fetch the content of a URL with SSRF protections.

    Parameters
    ----------
    url : str
        The URL to fetch.  Must use HTTPS.
    allowed_domains : set[str] | None
        Optional allowlist of domains.  When provided, the hostname of *url*
        must appear in this set (exact match, case-insensitive).

    Returns
    -------
    str
        The response body (text).

    Raises
    ------
    SSRFError
        If the URL fails any security validation.
    requests.RequestException
        On network-level errors that are not SSRF-related.
    """

    # --- Step 1: structural & DNS validation ---
    parsed = _validate_url(url)

    # --- Step 2: optional domain allowlist ---
    hostname_lower = parsed.hostname.lower()
    if allowed_domains is not None:
        normalised = {d.lower() for d in allowed_domains}
        if hostname_lower not in normalised:
            raise SSRFError(
                f"Hostname '{hostname_lower}' is not in the allowed domain list."
            )

    # --- Step 3: make the request with strict settings ---
    session = requests.Session()
    session.max_redirects = MAX_REDIRECTS

    # Disable automatic redirect following so we can inspect each hop
    response = session.get(
        url,
        allow_redirects=False,
        timeout=REQUEST_TIMEOUT,
        stream=True,
        headers={
            "User-Agent": "IntegrationWebhookFetcher/1.0",
        },
    )

    # Block any redirect the server tried to issue
    _validate_redirect_target(response)

    # --- Step 4: read body with size limit ---
    content_length = response.headers.get("Content-Length")
    if content_length is not None:
        try:
            if int(content_length) > MAX_RESPONSE_BYTES:
                response.close()
                raise SSRFError(
                    f"Response Content-Length ({content_length}) exceeds "
                    f"limit of {MAX_RESPONSE_BYTES} bytes."
                )
        except ValueError:
            pass  # non-integer Content-Length; we'll enforce during read

    chunks = []
    bytes_read = 0
    for chunk in response.iter_content(chunk_size=8192, decode_unicode=False):
        bytes_read += len(chunk)
        if bytes_read > MAX_RESPONSE_BYTES:
            response.close()
            raise SSRFError(
                f"Response body exceeded limit of {MAX_RESPONSE_BYTES} bytes."
            )
        chunks.append(chunk)

    response.close()

    body = b"".join(chunks)
    encoding = response.encoding or "utf-8"
    return body.decode(encoding, errors="replace")


